```class Solution {
public:
    long long mostPoints(vector<vector<int>>& questions) {
        int n = questions.size();
        vector<long long> dp(n, 0);
        dp[0] = questions[0][0];
        for (int i = 1; i < n; i++) {
            dp[i] = max(dp[i-1], dp[max(0, i-questions[i][1]-1)]);
            dp[i] += questions[i][0];
        }
        return *max_element(dp.begin(), dp.end());
    }
};```
